+type Clause = (input: unknown) => { matched: boolean; value?: unknown };
+type Step = Clause | { tap: (result: unknown) => void };
+
+/**
+ * Creates a pattern matching expression that runs every matching clause.
+ */
+export function matchEach<const input, output = symbols.unset>(
+  value: input
+): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<
+  input,
+  output
+>;
+export function matchEach(value?: unknown): MatchEach<any, any> {
+  return new MatchEachExpression(arguments.length === 0 ? undefined : value) as any;
+}
+
+class MatchEachExpression<input, output> {
+  constructor(
+    private readonly boundInput: input | undefined,
+    private readonly steps: readonly Step[] = []
+  ) {}
+
+  with(...args: any[]): MatchEachExpression<input, output> {
+    const handler = args[args.length - 1];
+    const patterns = [args[0]];
+    let predicate: ((value: input) => unknown) | undefined;
+
+    if (args.length === 3 && typeof args[1] === 'function') {
+      predicate = args[1];
+    } else if (args.length > 2) {
+      patterns.push(...args.slice(1, -1));
+    }
+
+    const clause: Clause = (input) => {
+      let hasSelections = false;
+      const selected: Record<string, unknown> = {};
+      const select = (key: string, value: unknown) => {
+        hasSelections = true;
+        selected[key] = value;
+      };
+      const matched =
+        patterns.some((pattern) => matchPattern(pattern, input, select)) &&
+        (predicate ? Boolean(predicate(input as input)) : true);
+
+      if (!matched) return { matched: false };
+      const selections = hasSelections
+        ? symbols.anonymousSelectKey in selected
+          ? selected[symbols.anonymousSelectKey]
+          : selected
+        : input;
+      return { matched: true, value: handler(selections, input) };
+    };
+    return new MatchEachExpression(this.boundInput, [...this.steps, clause]);
+  }
+
+  when(predicate: any, handler: any): MatchEachExpression<input, output> {
+    const clause: Clause = (input) =>
+      predicate(input) ? { matched: true, value: handler(input, input) } : { matched: false };
+    return new MatchEachExpression(this.boundInput, [...this.steps, clause]);
+  }
+
+  tap(callback: (result: output) => void): MatchEachExpression<input, output> {
+    return new MatchEachExpression(this.boundInput, [...this.steps, { tap: callback }]);
+  }
