+  }
+
+  toFunction() {
+    return (input: input): output[] => this.evaluate(input, true) as output[];
+  }
+
+  toExhaustiveFunction() {
+    return this.toFunction();
+  }
+
+  toPartialFunction() {
+    return (input: input): output[] | undefined => {
+      const results = this.evaluate(input, false) as output[];
+      return results.length ? results : undefined;
